import Foundation

// Generated from app/landmarks.js — do not edit by hand; regenerate via scripts/gen_landmarks.
enum LandmarkType: String, Codable, CaseIterable {
    case city, peak, park, water, icon, wonder, border

    var glyph: String {
        switch self {
        case .city: return "building.2.fill"
        case .peak: return "mountain.2.fill"
        case .park: return "tree.fill"
        case .water: return "water.waves"
        case .icon: return "star.circle.fill"
        case .wonder: return "sparkles"
        case .border: return "flag.2.crossed.fill"
        }
    }
}

struct Landmark: Identifiable, Hashable {
    let id: Int
    let name: String
    let type: LandmarkType
    let tier: Int        // 1 = world-famous, 2 = regional, 3 = local
    let lat: Double
    let lon: Double
    let elevM: Double
}

